firmware_template.source:
#include "deep_sleep.h"
#include <esp_sleep.h>
void sleep_setup(){
  if(esp_sleep_get_wakeup_cause()!=ESP_SLEEP_WAKEUP_UNDEFINED)
    Serial.println("[sleep] Woke up!");
  else Serial.println("[sleep] First boot");
}
void sleep_for(uint64_t s){
  esp_sleep_enable_timer_wakeup(s*1000000ULL);
  Serial.printf("[sleep] Sleeping %llus\n",s);Serial.flush();
  esp_deep_sleep_start();
}
void sleep_until_pin(uint8_t p,bool lvl){
  esp_sleep_enable_ext0_wakeup((gpio_num_t)p,lvl?1:0);
  Serial.printf("[sleep] Waiting GPIO%d\n",p);Serial.flush();
  esp_deep_sleep_start();
}
bool sleep_was_wakeup(){return esp_sleep_get_wakeup_cause()!=ESP_SLEEP_WAKEUP_UNDEFINED;}
